import{_ as t,o as i,c as o,an as r}from"./chunks/framework.D5fFzH9V.js";const h=JSON.parse('{"title":"👩‍💻 Secure Coding Policy","description":"Secure coding requirements and OWASP checklist alignment for Syslifters projects.","frontmatter":{"title":"👩‍💻 Secure Coding Policy","description":"Secure coding requirements and OWASP checklist alignment for Syslifters projects."},"headers":[],"relativePath":"organization/secure-coding.md","filePath":"organization/secure-coding.md"}'),s={name:"organization/secure-coding.md"};function n(a,e,c,l,d,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /organization/secure-coding.md for this page in Markdown format</div><h1 id="👩‍💻-secure-coding-policy" tabindex="-1">👩‍💻 Secure Coding Policy <a class="header-anchor" href="#👩‍💻-secure-coding-policy" aria-label="Permalink to &quot;👩‍💻 Secure Coding Policy&quot;">​</a></h1><p>We adhere to the <a href="https://owasp.org/www-project-secure-coding-practices-quick-reference-guide/stable-en/02-checklist/05-checklist" target="_blank" rel="noreferrer">OWASP Secure Coding Practices Checklist</a> and improve security following a risk-based approach and continuous improvement process.</p><p>Additionally, the following requirements must be met:</p><ul><li>All API endpoints must be added to <code>test_api.py</code><ul><li>We limit endpoints to certain user permissions using <code>permission_classes</code> in <code>views.py</code></li><li>This ensures that only users with defined permission levels can use the endpoints</li><li>If this is not possible, explicit test cases must be defined</li></ul></li><li>If users with the same permission level can use one endpoint, but only with a limited dataset (e.g., list their own projects, but not those of others), this must be covered by explicit test cases. <ul><li>We limit the available dataset using <code>get_queryset</code> methods in <code>views.py</code> perferably using <code>only_permitted</code> methods (in <code>queryset.py</code>).</li></ul></li></ul><p>This policy applies to the projects:</p><ul><li><a href="https://docs.sysreptor.com/" target="_blank" rel="noreferrer">SysReptor</a></li><li><a href="https://sysreptor.com/" target="_blank" rel="noreferrer">SysReptor Portal</a></li><li><a href="https://sysleaks.com/" target="_blank" rel="noreferrer">SysLeaks</a></li></ul><p>Last reviewed: 13/04/2026</p>',8)])])}const m=t(s,[["render",n]]);export{h as __pageData,m as default};
